import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import socket from '../socket/socket';
import axios from 'axios';

const TeamDashboard = () => {
  const { user, token } = useAuth();
  const [balance, setBalance] = useState(user?.coins || 0);
  const [bidAmount, setBidAmount] = useState('');
  const [roundActive, setRoundActive] = useState(false);
  const [message, setMessage] = useState('');
  const [leaderboard, setLeaderboard] = useState([]);

  useEffect(() => {
    socket.on('round-started', () => setRoundActive(true));
    socket.on('round-ended', () => setRoundActive(false));
    socket.on('leaderboard-update', fetchLeaderboard);

    fetchLeaderboard();

    return () => {
      socket.off('round-started');
      socket.off('round-ended');
      socket.off('leaderboard-update');
    };
  }, []);

  const fetchLeaderboard = async () => {
    try {
      const res = await axios.get('/api/team/leaderboard');
      setLeaderboard(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleBid = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/team/bid', { amount: parseInt(bidAmount) }, {
        headers: { 'x-auth-token': token }
      });
      setMessage('Bid placed!');
      setBidAmount('');
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Error placing bid');
    }
  };

  return (
    <div className="team-dashboard">
      <h2>Team: {user?.teamName}</h2>
      <div className="coin-display">💰 {balance} coins</div>

      {roundActive ? (
        <form onSubmit={handleBid}>
          <input
            type="number"
            placeholder="Enter bid amount"
            value={bidAmount}
            onChange={(e) => setBidAmount(e.target.value)}
            min="1"
            required
          />
          <button type="submit">Place Bid</button>
        </form>
      ) : (
        <p>Bidding is closed. Wait for next round.</p>
      )}
      {message && <p>{message}</p>}

      <h3>Leaderboard</h3>
      <table>
        <thead>
          <tr><th>Rank</th><th>Team</th><th>Coins</th></tr>
        </thead>
        <tbody>
          {leaderboard.map((team, idx) => (
            <tr key={team._id}>
              <td>{idx+1}</td>
              <td>{team.teamName}</td>
              <td>{team.coins}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default TeamDashboard;
